const PROCESSING_FEE = 5;

const itemBasePremium = (item: any): number => {
  if (item.type === "sword") {
    return 100;
  }
  if (item.type === "amulet") {
    return 60;
  }
  if (item.type === "staff") {
    return 80;
  }
  return 0;
};

const calculateQuotePremium = (items: any[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0) + PROCESSING_FEE;

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      return { premium: calculateQuotePremium(step.items) };
    }
  });
  return { results };
}

