import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("should charge only the 5 G processing fee for an empty item list", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("should compute base premium for a single sword (100 G + 5 G fee = 105 G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 105 }] });
    });
    it("should compute base premium for a single amulet (60 G + 5 G fee = 65 G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 65 }] });
    });
    it("should compute base premium for a single staff (80 G + 5 G fee = 85 G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 85 }] });
    });
    it("should compute base premium for a single potion (40 G + 5 G fee = 45 G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 45 }] });
    });
    it.todo("should compute base premium for a single component (25 G + 5 G fee = 30 G)");
    it.todo("should sum base premiums for multiple items in a policy");
  });

  describe("Quote - component blocks", () => {
    it.todo("should charge 50 G base premium for 2 runes (no block)");
    it.todo("should charge 60 G base premium for exactly 3 alike components (block applies)");
    it.todo("should charge 100 G base premium for 4 runes (no block)");
    it.todo("should charge 175 G base premium for 7 runes");
    it.todo("should not form a block from different component types (2 runes + 1 moonstone = 75 G)");
    it.todo("should form two separate blocks for 3 runes + 3 moonstones (120 G)");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("should add 50% cursed surcharge to a cursed item's base premium");
    it.todo("should add 30% high-enchantment surcharge for enchantment level >= 5");
    it.todo("should apply both cursed and high-enchantment surcharges to the same item");
    it.todo("should apply cursed surcharge only to the cursed item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("should apply 10% first-insurance surcharge to the policy base premium");
    it.todo("should apply 20% loyalty discount for customers with >= 2 years");
    it.todo("should apply 15% follow-up discount on second and subsequent quotes");
    it.todo("should stack loyalty, first-insurance, and follow-up modifiers");
  });

  describe("Quote - rounding", () => {
    it.todo("should round premium up to whole G in MHPCO's favor");
  });

  describe("Quote - integration", () => {
    it.todo("should compute 165 G for newcomer with cursed sword (steel, enchantment 3)");
    it.todo("should compute 160 G for long-standing customer's second contract with cursed sword (enchantment 7)");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("should reimburse damage minus 100 G deductible for a regular item");
    it.todo("should reimburse damage to a component minus deductible");
  });

  describe("Claim - special clauses", () => {
    it.todo("should reimburse at 50% for enchantment >= 8, then subtract deductible");
    it.todo("should fully reimburse dragon-material items, then subtract deductible");
    it.todo("should apply 50% rule when both enchantment >= 8 and dragon material");
  });

  describe("Claim - multiple damages", () => {
    it.todo("should apply deductible separately per damaged item in a single event");
  });

  describe("Claim - cap", () => {
    it.todo("should cap total payout at 2x insurance sum");
    it.todo("should track remaining cap across successive claims on the same policy");
  });

  describe("Claim - rounding", () => {
    it.todo("should round payout down to whole G in MHPCO's favor");
  });

  describe("Error handling", () => {
    it.todo("should reject unknown item type in a quote");
    it.todo("should reject claim for item not in policy");
    it.todo("should reject claim with more damages of a type than insured");
    it.todo("should reject claim with negative damage amount");
  });
});

