const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const isComponent = (item: any): boolean => !(item.type in MAIN_ITEM_PREMIUMS);

const calculateQuotePremium = (items: any[]): number => {
  let basePremium = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      basePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
    }
  }

  for (const count of Object.values(componentCounts)) {
    if (count === BLOCK_SIZE) {
      basePremium += BLOCK_PREMIUM;
    } else {
      basePremium += count * COMPONENT_PREMIUM;
    }
  }

  return basePremium + PROCESSING_FEE;
};

